 16→
 17→/** Result of instrumenting a source file. */
 18→export interface InstrumentResult {
 19→  /** The full instrumented source code. */
 20→  instrumentedSource: string;
 21→  /** The name of the line-recording function injected into the code. */
 22→  recordFunctionName: string;
 23→  /** The name of the branch-recording function injected into the code. */
 24→  branchFunctionName: string;
 25→  /** Total number of branch points instrumented. */
 26→  branchCount: number;
 27→  /** Number of unique executable statement lines instrumented with __shatter_record(). */
 28→  instrumentableLineCount: number;
 29→}
 30→
 31→/**
 32→ * The name of the mock call recording function inserted into instrumented code.
 33→ * Signature: __shatter_mock_call(module, symbol, args, returnValue) → void
 34→ */
 35→export const MOCK_CALL_FUNCTION = "__shatter_mock_call";
 36→
 37→/**
 38→ * The name of the global mock registry object.
 39→ * Maps "module:symbol" to mock functions.
 40→ */
 41→export const MOCK_REGISTRY = "__shatter_mocks";
 42→
 43→/**
 44→ * The name of the line-recording function inserted into instrumented code.
 45→ * Callers must define this function before executing instrumented code.
 46→ */
 47→export const RECORD_FUNCTION = "__shatter_record";
 48→
 49→/**
 50→ * The name of the branch-recording function inserted into instrumented code.
 51→ * Signature: __shatter_branch(branchId, line, conditionResult, symExpr) → boolean
 52→ */
 53→export const BRANCH_FUNCTION = "__shatter_branch";
 54→
 55→/**
 56→ * The name of the scope-event recording function inserted into instrumented code.
 57→ * Signature: __shatter_scope_event(scopeId, kind) → void
 58→ */
