 11→// transformFile walks the AST and inserts line recording, branch recording,
 12→// and scope event calls. If funcName is non-nil, only the named function is
 13→// instrumented. Returns the number of branches instrumented.
 14→func transformFile(fset *token.FileSet, file *ast.File, funcName *string) int {
 15→	branchID := 0
 16→	loopID := 0
 17→	callSiteID := 0
 18→	for _, decl := range file.Decls {
 19→		fn, ok := decl.(*ast.FuncDecl)
 20→		if !ok || fn.Body == nil {
 21→			continue
 22→		}
 23→		if funcName != nil && fn.Name.Name != *funcName {
 24→			continue
 25→		}
 26→		params := buildParamSet(fn)
 27→
 28→		// Inject call_enter/call_exit for the top-level function.
 29→		id := callSiteID
 30→		callSiteID++
 31→		fn.Body.List = append([]ast.Stmt{
 32→			makeScopeRecordStmt("call_enter", id),
 33→			makeDeferScopeRecordStmt("call_exit", id),
 34→		}, fn.Body.List...)
 35→
 36→		transformBlock(fset, fn.Body, params, &branchID, &loopID, &callSiteID)
 37→	}
 38→	return branchID
 39→}
 40→
 41→// buildParamSet extracts parameter names from a function declaration.
 42→func buildParamSet(fn *ast.FuncDecl) map[string]bool {
 43→	params := make(map[string]bool)
 44→	if fn.Type.Params == nil {
 45→		return params
 46→	}
 47→	for _, field := range fn.Type.Params.List {
 48→		for _, name := range field.Names {
 49→			params[name.Name] = true
 50→		}
 51→	}
 52→	return params
 53→}
 54→
 55→// transformBlock instruments a block statement by inserting line recording
 56→// before each statement, wrapping branch conditions, and adding scope markers.
 57→func transformBlock(fset *token.FileSet, block *ast.BlockStmt, params map[string]bool, branchID, loopID, callSiteID *int) {
 58→	if block == nil {
 59→		return
 60→	}
 61→	var newList []ast.Stmt
 62→	for _, stmt := range block.List {
 63→		line := fset.Position(stmt.Pos()).Line
 64→		newList = append(newList, makeLineRecordCall(line))
 65→		switch s := stmt.(type) {
 66→		case *ast.IfStmt:
 67→			transformIfStmt(fset, s, params, branchID, loopID, callSiteID)
 68→		case *ast.SwitchStmt:
 69→			transformSwitchStmt(fset, s, params, branchID, loopID, callSiteID)
 70→		case *ast.ForStmt:
