 80→/** Cache of compiled modules to avoid re-transpiling on every execute call. */
 81→const compiledModuleCache = new Map<string, Record<string, unknown>>();
 82→
 83→/**
 84→ * Proxy console used in VM sandboxes. Delegates all calls to `consoleTarget`,
 85→ * which can be swapped at execution time to capture output as side effects.
 86→ */
 87→let consoleTarget: Console = console;
 88→
 89→const consoleProxy = new Proxy(console, {
 90→  get(_target, prop, receiver) {
 91→    const value = Reflect.get(consoleTarget, prop, receiver);
 92→    if (typeof value === "function") {
 93→      return value.bind(consoleTarget);
 94→    }
 95→    return value;
 96→  },
 97→});
