  3→use std::collections::HashSet;
  4→
  5→use crate::types::ComplexKind;
  6→use serde::{Deserialize, Serialize};
  7→
  8→/// A symbolic expression representing a constraint on function inputs.
  9→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 10→#[serde(tag = "kind", rename_all = "snake_case")]
 11→pub enum SymExpr {
 12→    /// Reference to a function parameter, with optional field path.
 13→    /// e.g., param "config", path ["timeout"] represents config.timeout
 14→    Param {
 15→        name: String,
 16→        #[serde(default)]
 17→        path: Vec<String>,
 18→    },
 19→
 20→    /// A literal constant value.
 21→    Const(ConstValue),
 22→
 23→    /// Binary operation: left op right.
 24→    BinOp {
 25→        op: BinOpKind,
 26→        left: Box<SymExpr>,
 27→        right: Box<SymExpr>,
 28→    },
 29→
 30→    /// Unary operation: op operand.
 31→    UnOp {
 32→        op: UnOpKind,
 33→        operand: Box<SymExpr>,
 34→    },
 35→
 36→    /// Method/function call with symbolic arguments.
 37→    Call {
 38→        name: String,
 39→        receiver: Option<Box<SymExpr>>,
 40→        args: Vec<SymExpr>,
 41→    },
 42→
 43→    /// Could not be tracked symbolically — fall back to fuzzing.
 44→    Unknown,
 45→}
 46→
 47→/// A concrete constant value in a symbolic expression.
 48→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 49→#[serde(tag = "type", content = "value", rename_all = "snake_case")]
 50→pub enum ConstValue {
 51→    Int(i64),
 52→    Float(f64),
 53→    Str(String),
 54→    Bool(bool),
