 99→/// Collect all parameter names referenced in a symbolic expression tree.
100→/// Used for branch-parameter attribution — identifying which parameters
101→/// influence a given branch condition.
102→pub fn extract_param_names(expr: &SymExpr) -> HashSet<String> {
103→    let mut names = HashSet::new();
104→    collect_param_names(expr, &mut names);
105→    names
106→}
107→
108→fn collect_param_names(expr: &SymExpr, names: &mut HashSet<String>) {
109→    match expr {
110→        SymExpr::Param { name, .. } => {
111→            names.insert(name.clone());
112→        }
113→        SymExpr::Const(_) | SymExpr::Unknown => {}
114→        SymExpr::BinOp { left, right, .. } => {
115→            collect_param_names(left, names);
116→            collect_param_names(right, names);
117→        }
118→        SymExpr::UnOp { operand, .. } => {
119→            collect_param_names(operand, names);
120→        }
121→        SymExpr::Call {
122→            receiver, args, ..
123→        } => {
124→            if let Some(r) = receiver {
125→                collect_param_names(r, names);
126→            }
127→            for arg in args {
128→                collect_param_names(arg, names);
129→            }
130→        }
131→    }
132→}
