252→/// Convert a `SymExpr` into a Z3 AST node, declaring variables as needed.
253→///
254→/// `hint_sort` is used to determine the sort of `Param` nodes when no other
255→/// information is available.
256→///
257→/// Must be called within a `z3::with_z3_config` block or with the default
258→/// thread-local Z3 context active.
259→fn to_z3_expr(
260→    vars: &mut VarTable,
261→    expr: &SymExpr,
262→    hint_sort: Sort,
263→) -> Result<Z3Ast, SolverError> {
264→    match expr {
265→        SymExpr::Param { name, path } => {
266→            let var_name = param_var_name(name, path);
267→            // Use declared param sort to prevent sort mismatches (e.g. string params
268→            // declared as Int when they appear inside .length). Only override hint_sort
269→            // when the declared sort is categorically different (Str vs numeric/bool).
270→            // For numeric sorts (Int/Real/Float), prefer the comparison context's hint
271→            // since TS `number` maps to Float but constraints often use Int comparisons.
272→            let sort = match vars.param_sorts.get(&var_name).copied() {
273→                Some(declared) if !sorts_compatible(declared, hint_sort) => declared,
274→                _ => hint_sort,
275→            };
276→            match sort {
277→                Sort::Int => Ok(Z3Ast::Int(vars.get_or_create_int(&var_name))),
278→                Sort::Real => Ok(Z3Ast::Real(vars.get_or_create_real(&var_name))),
279→                Sort::Bool => Ok(Z3Ast::Bool(vars.get_or_create_bool(&var_name))),
280→                Sort::Str => Ok(Z3Ast::Str(vars.get_or_create_string(&var_name))),
281→            }
282→        }
283→
284→        SymExpr::Const(c) => match c {
285→            ConstValue::Int(v) => Ok(Z3Ast::Int(Int::from_i64(*v))),
286→            ConstValue::Float(v) => {
287→                let scaled = (*v * 1_000_000.0).round() as i64;
288→                Ok(Z3Ast::Real(Real::from_rational(scaled, 1_000_000)))
289→            }
290→            ConstValue::Str(s) => Ok(Z3Ast::Str(Z3String::from_str(s).map_err(|_| {
291→                SolverError::Unsupported("failed to create Z3 string constant".into())
292→            })?)),
293→            ConstValue::Bool(b) => Ok(Z3Ast::Bool(Bool::from_bool(*b))),
294→            ConstValue::Null | ConstValue::Undefined => Ok(Z3Ast::Int(Int::from_i64(0))),
295→            // Complex constants unwrap to their repr for solving
296→            ConstValue::Complex { repr, .. } => {
297→                let unwrapped = SymExpr::Const(*repr.clone());
298→                to_z3_expr(vars, &unwrapped, hint_sort)
299→            }
300→        },

 800→/// the result is an error, unsat, or when all solved values match their param types.
 801→/// A mismatch (e.g. `ConcreteValue::Int` for a `TypeInfo::Str` param) returns `false`.
 802→fn solved_values_match_param_types(
 803→    result: Result<&SolveResult, &SolverError>,
 804→    param_infos: &[ParamInfo],
 805→) -> bool {
 806→    let solved = match result {
 807→        Ok(SolveResult::Sat(map)) => map,
 808→        // Errors and Unsat trivially satisfy the postcondition.
 809→        _ => return true,
 810→    };
 811→    let param_map: HashMap<&str, &TypeInfo> = param_infos
 812→        .iter()
 813→        .map(|p| (p.name.as_str(), &p.typ))
 814→        .collect();
 815→    for (name, value) in solved {
 816→        if let Some(ty) = param_map.get(name.as_str())
 817→            && !concrete_value_matches_type(value, ty)
 818→        {
 819→            return false;
 820→        }
 821→        // Solved variables not in param_infos are sub-paths (e.g. "config.timeout")
 822→        // or synthesized — no type to check against.
 823→    }
 824→    true
 825→}
 826→
 827→/// Whether a `ConcreteValue` is compatible with a `TypeInfo`.
 828→fn concrete_value_matches_type(value: &ConcreteValue, ty: &TypeInfo) -> bool {
 829→    match (value, ty) {
 830→        // Numeric types are interchangeable — Z3 may solve a Float param as Int
 831→        // when the constraints only use integer comparisons, and vice versa.
 832→        (ConcreteValue::Int(_) | ConcreteValue::Float(_), TypeInfo::Int | TypeInfo::Float) => true,
 833→        (ConcreteValue::Str(_), TypeInfo::Str) => true,
 834→        (ConcreteValue::Bool(_), TypeInfo::Bool) => true,
 835→        // Nullable<inner> — the solved value should match the inner type
 836→        (_, TypeInfo::Nullable { inner }) => concrete_value_matches_type(value, inner),
 837→        // Complex value wraps a repr that Z3 solved — accept any complex match.
 838→        (ConcreteValue::Complex { .. }, TypeInfo::Complex { .. }) => true,
 839→        // Int is the Z3 default for types it can't represent (arrays, objects, unions,
 840→        // unknown, opaque). Accept Int for any non-primitive type.
 841→        (ConcreteValue::Int(_), _) => {
 842→            !matches!(ty, TypeInfo::Str | TypeInfo::Bool)
 843→        }
 844→        _ => false,
 845→    }
 846→}
 847→
 848→/// Solve a list of path constraints, negating the constraint at `negate_index`
 849→/// to explore a new execution path.
 850→///
 851→/// All constraints before `negate_index` are asserted as-is (the prefix), and
 852→/// the constraint at `negate_index` is negated. This is the standard concolic
 853→/// strategy: keep the path prefix and flip the last branch.
 854→///
 855→/// Returns `SolveResult::Sat` with concrete variable assignments if satisfiable,
 856→/// or `SolveResult::Unsat` if no inputs can reach the negated path.
 857→#[requires(negate_index < constraints.len(), "negate_index must be within constraints bounds")]
 858→#[contracts::ensures(solved_values_match_param_types(ret.as_ref(), param_infos),
 859→    "solved value types must be compatible with declared ParamInfo types")]
 860→pub fn solve_for_new_path(
 861→    constraints: &[SymExpr],
 862→    negate_index: usize,
 863→    solver_timeout_ms: Option<u64>,
 864→    param_infos: &[ParamInfo],
 865→) -> Result<SolveResult, SolverError> {
 866→    if negate_index >= constraints.len() {
 867→        return Err(SolverError::Unsupported(format!(
 868→            "negate_index {negate_index} out of bounds (len={})",
 869→            constraints.len()
 870→        )));
 871→    }
 872→
 873→    // Debug-only: verify constraint param names exist in param_infos when
 874→    // param_infos is non-empty. Unknown params get default Int sort in Z3,
 875→    // which silently produces wrong solutions for String/Bool params.
 876→    #[cfg(debug_assertions)]
 877→    if !param_infos.is_empty() {
 878→        let known: std::collections::HashSet<&str> =
 879→            param_infos.iter().map(|p| p.name.as_str()).collect();
 880→        for constraint in constraints {
 881→            for name in crate::sym_expr::extract_param_names(constraint) {
 882→                // Sub-path params (e.g. "config.timeout") won't match top-level names
 883→                if !name.contains('.') {
 884→                    debug_assert!(
 885→                        known.contains(name.as_str()),
 886→                        "constraint references unknown param {name:?}, \
 887→                         known params: {known:?}"
 888→                    );
 889→                }
 890→            }
 891→        }
 892→    }
 893→
 894→    let mut cfg = Config::new();
 895→    if let Some(ms) = solver_timeout_ms {
 896→        cfg.set_timeout_msec(ms);
 897→    }
 898→    let param_sorts = build_param_sorts(param_infos);
 899→    z3::with_z3_config(&cfg, || {
 900→        let solver = Solver::new();
 901→        let mut vars = VarTable::new(param_sorts.clone());
 902→
 903→        // Assert the prefix constraints as-is.
 904→        for constraint in &constraints[..negate_index] {
 905→            let sort = infer_operand_sort(constraint);
 906→            let bool_expr = to_z3_bool_constraint(&mut vars, constraint, sort)?;
 907→            solver.assert(&bool_expr);
 908→        }
 909→
 910→        // Negate the target constraint.
 911→        let target = &constraints[negate_index];
 912→        let sort = infer_operand_sort(target);
 913→        let target_bool = to_z3_bool_constraint(&mut vars, target, sort)?;
 914→        solver.assert(target_bool.not());
 915→
 916→        check_and_extract(&solver, &vars)
 917→    })
 918→}
 919→
 920→/// Solve a set of constraints directly (without negation).
 921→///
 922→/// Useful for checking satisfiability of a complete constraint set.
 923→pub fn solve_constraints(
 924→    constraints: &[SymExpr],
 925→    solver_timeout_ms: Option<u64>,
 926→    param_infos: &[ParamInfo],
 927→) -> Result<SolveResult, SolverError> {
 928→    let mut cfg = Config::new();
 929→    if let Some(ms) = solver_timeout_ms {
 930→        cfg.set_timeout_msec(ms);
 931→    }
 932→    let param_sorts = build_param_sorts(param_infos);
 933→    z3::with_z3_config(&cfg, || {
 934→        let solver = Solver::new();
 935→        let mut vars = VarTable::new(param_sorts.clone());
 936→
 937→        for constraint in constraints {
 938→            let sort = infer_operand_sort(constraint);
 939→            let bool_expr = to_z3_bool_constraint(&mut vars, constraint, sort)?;
 940→            solver.assert(&bool_expr);
 941→        }
 942→
 943→        check_and_extract(&solver, &vars)
 944→    })
 945→}
 946→
 947→fn to_z3_bool_constraint(
 948→    vars: &mut VarTable,
 949→    expr: &SymExpr,
 950→    sort: Sort,
 951→) -> Result<Bool, SolverError> {
 952→    let z3_expr = to_z3_expr(vars, expr, sort)?;
 953→    match z3_expr {
 954→        Z3Ast::Bool(b) => Ok(b),
 955→        _ => Err(SolverError::TypeMismatch {
 956→            expected: "Bool".into(),
 957→            actual: "non-Bool constraint".into(),
 958→        }),
 959→    }
 960→}
 961→
 962→fn check_and_extract(solver: &Solver, vars: &VarTable) -> Result<SolveResult, SolverError> {
 963→    match solver.check() {
 964→        SatResult::Sat => {
 965→            let model = solver.get_model().ok_or_else(|| {
 966→                SolverError::Unknown("solver returned sat but no model available".into())
 967→            })?;
 968→            let values = extract_concrete_values(&model, vars);
 969→            Ok(SolveResult::Sat(values))
 970→        }
 971→        SatResult::Unsat => Ok(SolveResult::Unsat),
 972→        SatResult::Unknown => Err(SolverError::Unknown(
 973→            solver
 974→                .get_reason_unknown()
 975→                .unwrap_or_else(|| "no reason given".into()),
 976→        )),
 977→    }
 978→}
