 921→///
 922→/// Useful for checking satisfiability of a complete constraint set.
 923→pub fn solve_constraints(
 924→    constraints: &[SymExpr],
 925→    solver_timeout_ms: Option<u64>,
 926→    param_infos: &[ParamInfo],
 927→) -> Result<SolveResult, SolverError> {
 928→    let mut cfg = Config::new();
 929→    if let Some(ms) = solver_timeout_ms {
 930→        cfg.set_timeout_msec(ms);
 931→    }
 932→    let param_sorts = build_param_sorts(param_infos);
 933→    z3::with_z3_config(&cfg, || {
 934→        let solver = Solver::new();
 935→        let mut vars = VarTable::new(param_sorts.clone());
 936→
 937→        for constraint in constraints {
 938→            let sort = infer_operand_sort(constraint);
 939→            let bool_expr = to_z3_bool_constraint(&mut vars, constraint, sort)?;
 940→            solver.assert(&bool_expr);
 941→        }
 942→
 943→        check_and_extract(&solver, &vars)
 944→    })
