1448→/// Field-level crossover for objects: each field independently chosen from A or B.
1449→fn crossover_object(
1450→    a: &Value,
1451→    b: &Value,
1452→    fields: &[(String, TypeInfo)],
1453→    rng: &mut impl Rng,
1454→) -> (Value, Value) {
1455→    let obj_a = a.as_object();
1456→    let obj_b = b.as_object();
1457→
1458→    // If either isn't actually an object, fall back to uniform swap
1459→    let (Some(obj_a), Some(obj_b)) = (obj_a, obj_b) else {
1460→        return if rng.random_bool(0.5) {
1461→            (a.clone(), b.clone())
1462→        } else {
1463→            (b.clone(), a.clone())
1464→        };
1465→    };
1466→
1467→    let mut c1 = serde_json::Map::new();
1468→    let mut c2 = serde_json::Map::new();
1469→
1470→    for (name, _typ) in fields {
1471→        let val_a = obj_a.get(name);
1472→        let val_b = obj_b.get(name);
1473→        match (val_a, val_b) {
1474→            (Some(va), Some(vb)) => {
1475→                if rng.random_bool(0.5) {
1476→                    c1.insert(name.clone(), va.clone());
1477→                    c2.insert(name.clone(), vb.clone());
1478→                } else {
1479→                    c1.insert(name.clone(), vb.clone());
1480→                    c2.insert(name.clone(), va.clone());
1481→                }
1482→            }
1483→            (Some(v), None) | (None, Some(v)) => {
1484→                // Only one parent has the field — give to one child
1485→                if rng.random_bool(0.5) {
1486→                    c1.insert(name.clone(), v.clone());
1487→                } else {
1488→                    c2.insert(name.clone(), v.clone());
1489→                }
1490→            }
1491→            (None, None) => {}
1492→        }
1493→    }
1494→
1495→    (Value::Object(c1), Value::Object(c2))
1496→}
