 25→/// Map parameter names from a branch constraint to their indices in `param_infos`.
 26→///
 27→/// For `SymConstraint::Expr`, walks the symbolic expression tree to extract
 28→/// referenced parameter names, then resolves each to its positional index.
 29→/// Returns an empty vec for `Unknown` constraints (no symbolic info available).
 30→pub fn identify_blocking_params(
 31→    constraint: &SymConstraint,
 32→    param_infos: &[ParamInfo],
 33→) -> Vec<usize> {
 34→    let expr = match constraint {
 35→        SymConstraint::Expr { expr } => expr,
 36→        SymConstraint::Unknown { .. } => return vec![],
 37→    };
 38→
 39→    let names = extract_param_names(expr);
 40→    let mut indices: Vec<usize> = names
 41→        .iter()
 42→        .filter_map(|name| param_infos.iter().position(|p| p.name == *name))
 43→        .collect();
 44→    indices.sort_unstable();
 45→    indices.dedup();
 46→    indices
 47→}
 48→
 49→/// Generate drilled inputs: pin non-blocking params at `best_prefix` values,
 50→/// intensively mutate only the blocking parameter(s).
 51→///
 52→/// If `blocking_params` is empty, falls back to mutating all parameters.
 53→/// Returns up to `count` mutated input vectors.
 54→pub fn generate_drilled_inputs(
 55→    best_prefix: &[Value],
 56→    blocking_params: &[usize],
 57→    param_infos: &[ParamInfo],
 58→    count: usize,
 59→    rng: &mut impl Rng,
 60→) -> Vec<Vec<Value>> {
 61→    if best_prefix.is_empty() || param_infos.is_empty() {
 62→        return vec![];
 63→    }
 64→
 65→    let targets: Vec<usize> = if blocking_params.is_empty() {
 66→        // No blocking info — mutate all params as fallback.
 67→        (0..best_prefix.len().min(param_infos.len())).collect()
 68→    } else {
 69→        blocking_params
 70→            .iter()
 71→            .copied()
 72→            .filter(|&i| i < best_prefix.len() && i < param_infos.len())
 73→            .collect()
 74→    };
 75→
 76→    if targets.is_empty() {
 77→        return vec![];
 78→    }
 79→
 80→    let mut results = Vec::with_capacity(count);
 81→    for _ in 0..count {
 82→        let mut inputs = best_prefix.to_vec();
 83→        for &idx in &targets {
 84→            inputs[idx] = mutate_value(&best_prefix[idx], &param_infos[idx].typ, &[], rng);
 85→        }
 86→        results.push(inputs);
 87→    }
 88→    results
 89→}
