 77→/// Score an execution result against a set of target (uncovered) branch IDs.
 78→///
 79→/// Returns a [`FitnessBreakdown`] with individual component scores and the
 80→/// weighted total, all normalized to 0.0–1.0.
 81→pub fn score(
 82→    result: &ExecuteResult,
 83→    target_branches: &HashSet<u32>,
 84→    context: &mut FitnessContext,
 85→    weights: &FitnessWeights,
 86→) -> FitnessBreakdown {
 87→    let coverage = coverage_score(&result.branch_path, target_branches.len());
 88→    let proximity = proximity_score(&result.branch_path, target_branches);
 89→    let unknown = unknown_bonus_score(&result.branch_path);
 90→    let novelty = novelty_score(&result.branch_path, context);
 91→
 92→    let weight_sum = weights.coverage + weights.proximity + weights.unknown_bonus + weights.novelty;
 93→    let total = if weight_sum > 0.0 {
 94→        (weights.coverage * coverage
 95→            + weights.proximity * proximity
 96→            + weights.unknown_bonus * unknown
 97→            + weights.novelty * novelty)
 98→            / weight_sum
 99→    } else {
100→        0.0
101→    };
102→
103→    FitnessBreakdown {
104→        coverage,
105→        proximity,
106→        unknown_bonus: unknown,
107→        novelty,
108→        total,
109→    }
110→}
