116→/// Fraction of unique branches hit relative to `target_count`.
117→fn coverage_score(branch_path: &[BranchDecision], target_count: usize) -> f64 {
118→    if target_count == 0 {
119→        return 1.0;
120→    }
121→    let unique: HashSet<u32> = branch_path.iter().map(|bd| bd.branch_id).collect();
122→    let ratio = unique.len() as f64 / target_count as f64;
123→    ratio.min(1.0)
124→}
