  1→//! Branch-distance fitness function for genetic search.
  2→//!
  3→//! Scores an [`ExecuteResult`] on four axes — branch coverage, proximity
  4→//! to uncovered target branches, unknown-branch exploration bonus, and
  5→//! path novelty — and combines them into a single 0.0–1.0 fitness value.
  6→
  7→use std::collections::HashSet;
  8→
  9→use crate::execution_record::{BranchDecision, SymConstraint};
 10→use crate::orchestrator::hash_branch_path;
 11→use crate::protocol::ExecuteResult;
 12→use crate::sym_expr::{BinOpKind, ConstValue, SymExpr};
 13→
 14→/// Weights for combining the four fitness components.
 15→///
 16→/// Defaults: coverage 0.30, proximity 0.40, unknown_bonus 0.10, novelty 0.20.
 17→#[derive(Debug, Clone)]
 18→pub struct FitnessWeights {
 19→    pub coverage: f64,
 20→    pub proximity: f64,
 21→    pub unknown_bonus: f64,
 22→    pub novelty: f64,
 23→}
 24→
 25→impl Default for FitnessWeights {
 26→    fn default() -> Self {
 27→        Self {
 28→            coverage: 0.30,
 29→            proximity: 0.40,
 30→            unknown_bonus: 0.10,
 31→            novelty: 0.20,
 32→        }
 33→    }
 34→}
 35→
 36→/// Breakdown of the four fitness components before weighting.
 37→#[derive(Debug, Clone)]
 38→pub struct FitnessBreakdown {
 39→    /// Fraction of unique branches hit relative to target count (0.0–1.0).
 40→    pub coverage: f64,
 41→    /// Average closeness to flipping target branches (0.0–1.0).
 42→    pub proximity: f64,
 43→    /// Bonus for reaching `SymConstraint::Unknown` branches (0.0–1.0).
 44→    pub unknown_bonus: f64,
 45→    /// 1.0 if this is a novel path, 0.0 if previously seen.
 46→    pub novelty: f64,
 47→    /// Weighted combination of the four components (0.0–1.0).
 48→    pub total: f64,
 49→}
 50→
 51→/// Mutable state tracking previously seen path hashes for novelty scoring.
 52→#[derive(Debug, Clone, Default)]
 53→pub struct FitnessContext {
 54→    seen_paths: HashSet<u64>,
 55→}
 56→
 57→impl FitnessContext {
 58→    pub fn new() -> Self {
 59→        Self::default()
 60→    }
 61→
 62→    /// Create a `FitnessContext` pre-seeded with already-seen path hashes.
 63→    ///
 64→    /// This allows sharing novelty state with the orchestrator's `covered_paths`,
 65→    /// so paths already discovered before fitness scoring starts are not scored
 66→    /// as novel.
 67→    pub fn from_seen_paths(seen_paths: HashSet<u64>) -> Self {
 68→        Self { seen_paths }
 69→    }
 70→
 71→    /// Record a path hash as seen, returning true if it was new.
 72→    pub fn mark_seen(&mut self, path_hash: u64) -> bool {
 73→        self.seen_paths.insert(path_hash)
 74→    }
 75→}
 76→
 77→/// Score an execution result against a set of target (uncovered) branch IDs.
 78→///
 79→/// Returns a [`FitnessBreakdown`] with individual component scores and the
 80→/// weighted total, all normalized to 0.0–1.0.
 81→pub fn score(
 82→    result: &ExecuteResult,
 83→    target_branches: &HashSet<u32>,
 84→    context: &mut FitnessContext,
 85→    weights: &FitnessWeights,
 86→) -> FitnessBreakdown {
 87→    let coverage = coverage_score(&result.branch_path, target_branches.len());
 88→    let proximity = proximity_score(&result.branch_path, target_branches);
 89→    let unknown = unknown_bonus_score(&result.branch_path);
 90→    let novelty = novelty_score(&result.branch_path, context);
 91→
 92→    let weight_sum = weights.coverage + weights.proximity + weights.unknown_bonus + weights.novelty;
 93→    let total = if weight_sum > 0.0 {
 94→        (weights.coverage * coverage
 95→            + weights.proximity * proximity
 96→            + weights.unknown_bonus * unknown
 97→            + weights.novelty * novelty)
 98→            / weight_sum
 99→    } else {
100→        0.0
101→    };
102→
103→    FitnessBreakdown {
104→        coverage,
105→        proximity,
106→        unknown_bonus: unknown,
107→        novelty,
108→        total,
109→    }
110→}
111→
112→// ---------------------------------------------------------------------------
113→// Component scorers
114→// ---------------------------------------------------------------------------
115→
116→/// Fraction of unique branches hit relative to `target_count`.
117→fn coverage_score(branch_path: &[BranchDecision], target_count: usize) -> f64 {
118→    if target_count == 0 {
119→        return 1.0;
120→    }
121→    let unique: HashSet<u32> = branch_path.iter().map(|bd| bd.branch_id).collect();
122→    let ratio = unique.len() as f64 / target_count as f64;
123→    ratio.min(1.0)
124→}
125→
126→/// Average closeness to flipping each target branch.
127→///
128→/// For each target: if reached in the trace, score = 1 − branch_distance.
129→/// If never reached, contributes 0.
130→fn proximity_score(branch_path: &[BranchDecision], targets: &HashSet<u32>) -> f64 {
131→    if targets.is_empty() {
132→        return 1.0;
133→    }
134→    let mut total = 0.0;
135→    for &target_id in targets {
136→        let closest = branch_path
137→            .iter()
138→            .filter(|bd| bd.branch_id == target_id)
139→            .map(|bd| branch_distance(&bd.constraint))
140→            .min_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
141→
142→        if let Some(dist) = closest {
143→            total += 1.0 - dist;
144→        }
145→    }
146→    total / targets.len() as f64
147→}
148→
149→/// Distance for a single branch constraint (0.0 = at target, 1.0 = far away).
150→fn branch_distance(constraint: &SymConstraint) -> f64 {
151→    match constraint {
152→        SymConstraint::Unknown { .. } => 0.5,
153→        SymConstraint::Expr { expr } => expr_distance(expr),
154→    }
155→}
156→
157→/// Distance derived from a symbolic expression.
158→fn expr_distance(expr: &SymExpr) -> f64 {
159→    match expr {
160→        SymExpr::BinOp { op, left, right } => {
161→            match (eval_to_f64(left), eval_to_f64(right)) {
162→                (Some(l), Some(r)) => comparison_distance(*op, l, r),
163→                _ => 0.5, // cannot evaluate — moderate distance
164→            }
165→        }
166→        SymExpr::UnOp {
167→            op: crate::sym_expr::UnOpKind::Not,
168→            operand,
169→        } => 1.0 - expr_distance(operand),
170→        _ => 0.5,
171→    }
172→}
173→
174→/// Standard branch-distance formula for comparison operators.
175→///
176→/// Uses the Korel (1990) approach: raw numeric distance normalized via
177→/// `d / (d + 1)` so the result is always in [0, 1).
178→fn comparison_distance(op: BinOpKind, left: f64, right: f64) -> f64 {
179→    let raw = match op {
180→        BinOpKind::Eq => (left - right).abs(),
181→        BinOpKind::Ne => {
182→            if (left - right).abs() < f64::EPSILON {
183→                1.0
184→            } else {
185→                0.0
186→            }
187→        }
188→        BinOpKind::Lt => {
189→            if left < right {
190→                0.0
191→            } else {
192→                left - right + 1.0
193→            }
194→        }
195→        BinOpKind::Le => {
196→            if left <= right {
197→                0.0
198→            } else {
199→                left - right
200→            }
201→        }
202→        BinOpKind::Gt => {
203→            if left > right {
204→                0.0
205→            } else {
206→                right - left + 1.0
207→            }
208→        }
209→        BinOpKind::Ge => {
210→            if left >= right {
211→                0.0
212→            } else {
213→                right - left
214→            }
215→        }
216→        _ => return 0.5, // non-comparison operator
217→    };
218→    normalize_distance(raw)
219→}
220→
221→/// Normalize a raw distance to [0.0, 1.0) via `d / (d + 1)`.
222→fn normalize_distance(d: f64) -> f64 {
223→    if d <= 0.0 {
224→        0.0
225→    } else {
226→        d / (d + 1.0)
227→    }
228→}
229→
230→/// Try to extract a numeric value from a constant expression.
231→fn eval_to_f64(expr: &SymExpr) -> Option<f64> {
232→    match expr {
233→        SymExpr::Const(ConstValue::Int(i)) => Some(*i as f64),
234→        SymExpr::Const(ConstValue::Float(f)) => Some(*f),
235→        SymExpr::Const(ConstValue::Bool(b)) => Some(if *b { 1.0 } else { 0.0 }),
236→        _ => None,
237→    }
238→}
239→
240→/// Reward executions that reach `Unknown` constraints (unsolvable by Z3).
241→///
242→/// Saturates at 5 unknown branches.
243→fn unknown_bonus_score(branch_path: &[BranchDecision]) -> f64 {
244→    let count = branch_path
245→        .iter()
246→        .filter(|bd| matches!(&bd.constraint, SymConstraint::Unknown { .. }))
247→        .count();
248→    if count == 0 {
249→        0.0
250→    } else {
251→        (count as f64).min(5.0) / 5.0
252→    }
253→}
254→
255→/// 1.0 for a never-before-seen path hash, 0.0 for a repeat.
256→fn novelty_score(branch_path: &[BranchDecision], context: &mut FitnessContext) -> f64 {
257→    let path_hash = hash_branch_path(branch_path);
258→    if context.seen_paths.insert(path_hash) {
259→        1.0
260→    } else {
261→        0.0
262→    }
263→}
