252→/// Convert a `SymExpr` into a Z3 AST node, declaring variables as needed.
253→///
254→/// `hint_sort` is used to determine the sort of `Param` nodes when no other
255→/// information is available.
256→///
257→/// Must be called within a `z3::with_z3_config` block or with the default
258→/// thread-local Z3 context active.
259→fn to_z3_expr(
260→    vars: &mut VarTable,
261→    expr: &SymExpr,
262→    hint_sort: Sort,
263→) -> Result<Z3Ast, SolverError> {
264→    match expr {
265→        SymExpr::Param { name, path } => {
266→            let var_name = param_var_name(name, path);
267→            // Use declared param sort to prevent sort mismatches (e.g. string params
268→            // declared as Int when they appear inside .length). Only override hint_sort
269→            // when the declared sort is categorically different (Str vs numeric/bool).
270→            // For numeric sorts (Int/Real/Float), prefer the comparison context's hint
271→            // since TS `number` maps to Float but constraints often use Int comparisons.
272→            let sort = match vars.param_sorts.get(&var_name).copied() {
273→                Some(declared) if !sorts_compatible(declared, hint_sort) => declared,
